    36	impl Position {
    37	    /// Returns `true` if the position is [`Tail`].
    38	    ///
    39	    /// [`Tail`]: Position::Tail
    40	    #[must_use]
    41	    pub fn is_tail(&self) -> bool {
    42	        matches!(self, Self::Tail)
    43	    }
