    45	    #[must_use]
    46	    pub fn ordering(&self) -> Ordering {
    47	        match self {
    48	            Self::Expression(ordering) => *ordering,
    49	            Self::Tail | Self::Assign(_) | Self::Statement => Ordering::Loose,
    50	        }
    51	    }
    52	}
