   261	pub(crate) fn array<'a, Elements: IntoIterator<Item = Document<'a>>>(
   262	    elements: Elements,
   263	) -> Document<'a> {
   264	    let elements = Itertools::intersperse(elements.into_iter(), break_(",", ", ")).collect_vec();
   265	    if elements.is_empty() {
   266	        // Do not add a trailing comma since that adds an 'undefined' element
   267	        "[]".to_doc()
   268	    } else {
   269	        docvec![
   270	            "[",
   271	            docvec![break_("", ""), elements].nest(INDENT),
   272	            break_(",", ""),
   273	            "]"
   274	        ]
   275	        .group()
   276	    }
   277	}
