   318	pub(crate) fn construct_record<'a>(
   319	    module: Option<&'a str>,
   320	    name: &'a str,
   321	    arguments: impl IntoIterator<Item = Document<'a>>,
   322	) -> Document<'a> {
   323	    let mut any_arguments = false;
   324	    let arguments = join(
   325	        arguments.into_iter().inspect(|_| {
   326	            any_arguments = true;
   327	        }),
   328	        break_(",", ", "),
   329	    );
   330	    let arguments = docvec![break_("", ""), arguments].nest(INDENT);
   331	    let name = if let Some(module) = module {
   332	        docvec!["$", module, ".", name]
   333	    } else {
   334	        name.to_doc()
   335	    };
   336	    if any_arguments {
   337	        docvec!["new ", name, "(", arguments, break_(",", ""), ")"].group()
   338	    } else {
   339	        docvec!["new ", name, "()"]
   340	    }
   341	}
