   458	pub(crate) fn record_constructor<'a>(
   459	    type_: Arc<Type>,
   460	    qualifier: Option<&'a str>,
   461	    name: &'a str,
   462	    arity: u16,
   463	    tracker: &mut UsageTracker,
   464	) -> Document<'a> {
   465	    if qualifier.is_none() && type_.is_result_constructor() {
   466	        if name == "Ok" {
   467	            tracker.ok_used = true;
   468	        } else if name == "Error" {
   469	            tracker.error_used = true;
   470	        }
   471	    }
   472	    if type_.is_bool() && name == "True" {
   473	        "true".to_doc()
   474	    } else if type_.is_bool() {
   475	        "false".to_doc()
   476	    } else if type_.is_nil() {
   477	        "undefined".to_doc()
   478	    } else if arity == 0 {
   479	        match qualifier {
   480	            Some(module) => docvec!["new $", module, ".", name, "()"],
   481	            None => docvec!["new ", name, "()"],
   482	        }
   483	    } else {
   484	        let vars = (0..arity).map(|i| eco_format!("var{i}").to_doc());
   485	        let body = docvec![
   486	            "return ",
   487	            construct_record(qualifier, name, vars.clone()),
   488	            ";"
   489	        ];
   490	        docvec![
   491	            docvec![wrap_arguments(vars), " => {", break_("", " "), body]
   492	                .nest(INDENT)
   493	                .append(break_("", " "))
   494	                .group(),
   495	            "}",
   496	        ]
   497	    }
   498	}
