        self.variables.expression_generator.current_scope_vars = old_scope;
        // Preserve the $ counter from the inner scope to avoid duplicates
        if let Some(count) = assign_var_count {
            let old_count = self.variables.expression_generator.current_scope_vars.get(&ASSIGNMENT_VAR_STR).copied().unwrap_or(0);
            if count > old_count {
                let _ = self.variables.expression_generator.current_scope_vars.insert(ASSIGNMENT_VAR_STR.into(), count);
            }
        }
